    'Vice President': ['todos', 'reports', 'roles', 'ways-to-help', 'resources'],
    'Secretary': ['todos', 'reports', 'roles', 'ways-to-help', 'resources'],
    'Sustaining Director': ['todos', 'reports', 'roles', 'ways-to-help', 'resources'],
